const request=require("supertest"),app=require("../src/app");describe("Component API",(()=>{test("GET /api/health returns ok",(async()=>{const t=await request(app).get("/api/health");expect(t.status).toBe(200),expect(t.body.ok).toBe(!0)})),test("POST /api/components validates payload without auth",(async()=>{const t=await request(app).post("/api/components").send({framework:"invalid-fw",component:"button"});expect(t.status).toBe(400),expect(t.body.ok).toBe(!1)})),test("POST /api/components validates component naming without auth",(async()=>{const t=await request(app).post("/api/components").send({framework:"react",component:"Bad Name"});expect(t.status).toBe(400),expect(t.body.ok).toBe(!1)})),test("POST /api/components requires component",(async()=>{const t=await request(app).post("/api/components").send({framework:"react"});expect(t.status).toBe(400),expect(t.body.ok).toBe(!1)})),test("GET /api/components/search validates query",(async()=>{const t=await request(app).get("/api/components/search");expect(t.status).toBe(400),expect(t.body.ok).toBe(!1)}))}));